module srt_divider (  
    input [15:0] dividend_inverted,  
    input [15:0] divisor,  
    output reg [15:0] quotient,  
    output reg [15:0] remainder  
);  
    always @(*) begin  
        if (divisor == 0) begin  
            quotient = 0;  
            remainder = dividend_inverted;  
        end else begin  
            // SRT division algorithm simplified for illustration purposes  
            quotient = dividend_inverted / divisor;  
            remainder = dividend_inverted % divisor;  
        end  
    end  
endmodule
